customCSS:
/* Theme Modal */
.modal { background: rgba(30,30,30,0.34) !important; backdrop-filter: blur(3px) !important; -webkit-backdrop-filter: blur(3px) !important; }
.modal-content { background: linear-gradient(180deg, rgba(255,255,255,0.98), rgba(242,242,242,0.98)) !important; border: 1px solid rgba(0,0,0,0.24) !important; border-radius: 8px !important; box-shadow: 0 18px 38px rgba(0,0,0,0.22), inset 0 1px 0 rgba(255,255,255,0.9) !important; color: #111 !important; }
.modal-title, .settings-title, .modal-content h4 { color: #6f5600 !important; }
.app-dialog-message, .trigger-description, .community-template .description { color: #111 !important; }
.import-hint, .settings-help, .hotkey-help, .range-labels, .community-template .task-count { color: #555 !important; }
.community-template { background: rgba(255,255,255,0.78) !important; border: 1px solid rgba(0,0,0,0.14) !important; }
.modal-btn.primary { background: #4169e1 !important; border: 1px solid #2f54c9 !important; color: #fff !important; }
.modal-btn.secondary { background: #f4f4f4 !important; border: 1px solid #bdbdbd !important; color: #111 !important; }
.modal-btn:hover { border-color: #4169e1 !important; box-shadow: 0 0 0 2px rgba(65,105,225,0.16) !important; }
.modal-content-dialog.app-dialog-tone-danger { border-color: #dc143c !important; }
.modal-content-dialog.app-dialog-tone-danger .modal-title { color: #b00024 !important; }
